+import { userEvent } from "@vitest/browser/context";
+import { type ReactNode } from "react";
+import { flushSync } from "react-dom";
+import { createRoot, type Root } from "react-dom/client";
+import { afterEach, describe, expect, it } from "vitest";
+
+import { AdditionVisualizer } from "./AdditionVisualizer";
+
+let root: Root | undefined;
+
+function renderInBrowser(children: ReactNode) {
+  const container = document.createElement("div");
+  document.body.append(container);
+
+  root = createRoot(container);
+  flushSync(() => {
+    root?.render(children);
+  });
+}
+
+afterEach(() => {
+  root?.unmount();
+  root = undefined;
+  document.body.replaceChildren();
+});
+
+describe("AdditionVisualizer", () => {
+  it("renders the addition demo and updates the result", async () => {
+    renderInBrowser(<AdditionVisualizer />);
+
+    expect(
+      document.querySelector("h1")?.textContent
+    ).toBe("Add Two Numbers");
+    expect(document.querySelector('[data-testid="sum"]')?.textContent).toBe(
+      "3"
+    );
+
+    const first = document.querySelector<HTMLInputElement>("#left-operand");
+    const second = document.querySelector<HTMLInputElement>("#right-operand");
+
+    expect(first).not.toBeNull();
+    expect(second).not.toBeNull();
+
+    await userEvent.fill(first as HTMLInputElement, "7");
+    await userEvent.fill(second as HTMLInputElement, "5");
+
+    expect(document.querySelector('[data-testid="sum"]')?.textContent).toBe(
+      "12"
+    );
+  });
+});
*** Add File: apps/web/src/components/AdditionVisualizer.tsx
+"use client";
+
+import { add } from "@demo/lib";
+import { useState } from "react";
+
+function toDisplayNumber(value: string): number {
+  const parsed = Number(value);
+
+  return Number.isFinite(parsed) ? parsed : 0;
+}
+
+function toUnits(value: number): number[] {
+  const bounded = Math.min(Math.max(Math.trunc(value), 0), 24);
+
+  return Array.from({ length: bounded }, (_, index) => index);
+}
+
+export function AdditionVisualizer() {
+  const [left, setLeft] = useState("1");
+  const [right, setRight] = useState("2");
+  const leftNumber = toDisplayNumber(left);
+  const rightNumber = toDisplayNumber(right);
+  const sum = add(leftNumber, rightNumber);
+
+  return (
+    <section className="addition-card" aria-labelledby="addition-heading">
+      <h1 id="addition-heading">Add Two Numbers</h1>
+      <p>
+        Enter two operands to see the shared math package calculate the result
+        and render the same value as a compact unit visualization.
+      </p>
+
+      <div className="addition-controls">
+        <label htmlFor="left-operand">
+          First number
+          <input
+            id="left-operand"
+            inputMode="decimal"
+            onChange={(event) => setLeft(event.currentTarget.value)}
+            type="number"
+            value={left}
+          />
+        </label>
+        <label htmlFor="right-operand">
+          Second number
+          <input
+            id="right-operand"
+            inputMode="decimal"
+            onChange={(event) => setRight(event.currentTarget.value)}
+            type="number"
+            value={right}
+          />
+        </label>
+      </div>
+
+      <div className="addition-result" aria-live="polite">
+        <span>Current result</span>
+        <span data-testid="sum">{sum}</span>
+      </div>
+
+      <div className="addition-visual" aria-label="Addition visualization">
+        <VisualizerRow label="First" units={toUnits(leftNumber)} tone="primary" />
+        <VisualizerRow label="Second" units={toUnits(rightNumber)} tone="secondary" />
+        <VisualizerRow label="Result" units={toUnits(sum)} tone="result" />
+      </div>
+    </section>
+  );
+}
+
+function VisualizerRow({
+  label,
+  tone,
+  units
+}: Readonly<{
+  label: string;
+  tone: "primary" | "secondary" | "result";
+  units: number[];
+}>) {
+  return (
+    <div className="addition-row">
+      <strong>{label}</strong>
+      <div className="addition-units">
+        {units.map((unit) => (
+          <span
+            aria-hidden="true"
+            className={tone === "primary" ? "addition-unit" : `addition-unit ${tone}`}
+            key={unit}
+          />
+        ))}
+      </div>
+    </div>
+  );
+}
*** Add File: apps/web/tests/e2e/addition.spec.ts
+import { expect, test } from "@playwright/test";
+
+test("updates the addition result live", async ({ page }) => {
+  await page.goto("/");
+
+  await expect(
+    page.getByRole("heading", { name: "Add Two Numbers" })
+  ).toBeVisible();
+  await expect(page.getByLabel("Addition visualization")).toBeVisible();
+  await expect(page.getByTestId("sum")).toHaveText("3");
+
+  await page.getByLabel("First number").fill("10");
+  await expect(page.getByTestId("sum")).toHaveText("12");
+
+  await page.getByLabel("Second number").fill("5");
+  await expect(page.getByTestId("sum")).toHaveText("15");
+});
